import React from 'react';
import { formatCurrency } from '../../utils/formatters';
import { getSlabRows } from '../../utils/slabUtils';

function SlabBreakdown({ salary }) {
  const { rows, surcharge } = getSlabRows(salary);
  return (
    <div className="slab-breakdown">
      <table>
        <thead>
          <tr>
            <th>Slab</th>
            <th>Taxable amount</th>
            <th>Rate</th>
            <th>Tax</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i} className="slab-row">
              <td>{r.label}</td>
              <td>{formatCurrency(r.amount)}</td>
              <td>{r.rate}</td>
              <td>{formatCurrency(r.tax)}</td>
            </tr>
          ))}
          {surcharge > 0 && (
            <tr className="slab-row surcharge-row">
              <td colSpan="2">Surcharge (5% on tax above ₹50,000)</td>
              <td>5%</td>
              <td>{formatCurrency(surcharge)}</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default SlabBreakdown;
